/**
 * Spell 加载器 · 从打包的 bundle 中读取（无需 R2）
 */


/**
 * 加载 spell 并注入所有依赖内容
 */
async function loadSpell(env, spellPath, variables = {}, opts = {}) {
  let text = BUNDLE[spellPath];
  if (!text) throw new Error(`Spell not found: ${spellPath}`);

  for (const [k, v] of Object.entries(variables)) {
    text = text.replaceAll(`{{${k}}}`, v || '');
  }

  text = injectTemplateRefs(text);
  text = injectSupportRefs(text);

  const outputConstraint = `

---
## 输出格式要求（必须遵守）

你的输出中如果包含多份文档或文件，请用以下分隔符标记每份文件的开始：

\`\`\`
===FILE: 文件名.md===
文件内容...
\`\`\`

如果只有一份主文档，直接输出内容即可，不需要分隔符。
`;

  return {
    system: text + outputConstraint,
    user: variables.USER_INPUT || variables.PRODUCT_REQUEST || '请按以上要求执行任务。',
  };
}

function injectTemplateRefs(text) {
  const patterns = [
    /Read\s+(?:.*?)templates\/([\w\-_.（）\u4e00-\u9fff]+\.md)/g,
    /读取\s+(?:.*?)templates\/([\w\-_.（）\u4e00-\u9fff]+\.md)/g,
    /加载\s+(?:.*?)templates\/([\w\-_.（）\u4e00-\u9fff]+\.md)/g,
  ];

  const refs = new Set();
  for (const pattern of patterns) {
    let match;
    while ((match = pattern.exec(text)) !== null) {
      refs.add(match[1]);
    }
  }

  if (refs.size === 0) return text;

  let injected = '\n\n---\n## 以下是已加载的 VELA 模板（直接参考，无需再读取文件）\n';
  for (const filename of refs) {
    const content = BUNDLE[`templates/${filename}`];
    if (content) {
      const truncated = content.length > 8000 ? content.slice(0, 8000) + '\n\n... (模板内容已截断)' : content;
      injected += `\n### ${filename}\n${truncated}\n`;
    }
  }

  for (const pattern of patterns) {
    text = text.replace(new RegExp(pattern.source, 'g'), '（模板已注入到 prompt 末尾，请直接参考）');
  }

  return text + injected;
}

function injectSupportRefs(text) {
  const pattern = /Read\s+(?:.*?)supports\/([\w\-_.（）\u4e00-\u9fff]+\.md)/g;
  const refs = new Set();
  let match;
  while ((match = pattern.exec(text)) !== null) {
    refs.add(match[1]);
  }

  if (refs.size === 0) return text;

  let injected = '\n\n---\n## 以下是已加载的支撑文档\n';
  for (const filename of refs) {
    const content = BUNDLE[`supports/${filename}`];
    if (content) {
      const truncated = content.length > 5000 ? content.slice(0, 5000) + '\n\n... (内容已截断)' : content;
      injected += `\n### ${filename}\n${truncated}\n`;
    }
  }

  text = text.replace(new RegExp(pattern.source, 'g'), '（支撑文档已注入到 prompt 末尾，请直接参考）');
  return text + injected;
}

async function loadIndustryExpert(env, industry) {
  if (!industry) return '';

  for (const [key, content] of Object.entries(BUNDLE)) {
    if (key.startsWith('industry-experts/') && key.includes(industry)) {
      return content;
    }
  }

  return BUNDLE['industry-experts/00_通用平台专家.md'] || '';
}


// ════════════════════════════════════════════════════
// 模块 4: output-parser.js (输出解析)
// ════════════════════════════════════════════════════

/**
 * 输出解析器 · 从 AI 输出中提取文档
 */

/**
 * 解析输出，按 ===FILE: xxx=== 分隔符拆分
 */
function parseOutputFiles(text, defaultFilename = '文档.md') {
  const FILE_SEP = /^===FILE:\s*(.+?)\s*===\s*$/gm;
  const markers = [];
  let match;
  while ((match = FILE_SEP.exec(text)) !== null) {
    markers.push({ filename: match[1], index: match.index, end: match.index + match[0].length });
  }

  if (markers.length === 0) {
    return [{ filename: defaultFilename, content: text.trim() }];
  }

  const files = [];
  const preContent = text.slice(0, markers[0].index).trim();
  if (preContent) files.push({ filename: defaultFilename, content: preContent });

  for (let i = 0; i < markers.length; i++) {
    const start = markers[i].end;
    const end = i + 1 < markers.length ? markers[i + 1].index : text.length;
    const content = text.slice(start, end).trim();
    if (content) files.push({ filename: markers[i].filename, content });
  }

  return files;
}

/**
 * 存文件到 R2（如果有 R2 绑定）
 */
async function saveFilesToR2(env, batchId, files) {
  if (!env?.R2) return files.map(f => ({ ...f, path: `projects/${batchId}/${f.filename}`, size: f.content.length }));
  const saved = [];
  for (const file of files) {
    const key = `projects/${batchId}/${file.filename}`;
    try { await env.R2.put(key, file.content); } catch (_) {}
    saved.push({ path: key, filename: file.filename, size: file.content.length });
  }
  return saved;
}

/**
 * 列出文件（R2 可选）
 */
async function listBatchFiles(env, batchId) {
  if (!env?.R2) return [];
  try {
    const list = await env.R2.list({ prefix: `projects/${batchId}/` });
    return (list.objects || []).map(obj => ({
      path: obj.key, filename: obj.key.replace(`projects/${batchId}/`, ''),
      size: obj.size, uploaded: obj.uploaded,
    }));
  } catch (_) { return []; }
}

async function readFile(env, path) {
  if (!env?.R2) return null;
  try { const obj = await env.R2.get(path); return obj ? await obj.text() : null; } catch (_) { return null; }
}


