/**
 * 状态管理 · 轻量版（KV 可选，没有也能跑）
 */

const RUNS = new Map();
const BATCHES = new Map();

async function createRun(env, runId, data) {
  const run = {
    run_id: runId, status: 'running', agent_key: data.agentKey || '',
    batch_id: data.batchId || '', product: data.product || '',
    industry: data.industry || '', mode: data.mode || 'lightning',
    created_at: Date.now(), completed_at: null, output_text: '',
  };
  RUNS.set(runId, run);
  if (env?.KV) { try { await env.KV.put(`run:${runId}`, JSON.stringify(run)); } catch (_) {} }
  return run;
}

async function updateRun(env, runId, updates) {
  let run = RUNS.get(runId);
  if (!run && env?.KV) { try { const r = await env.KV.get(`run:${runId}`); if (r) run = JSON.parse(r); } catch (_) {} }
  if (!run) return null;
  Object.assign(run, updates);
  RUNS.set(runId, run);
  if (env?.KV) { try { await env.KV.put(`run:${runId}`, JSON.stringify(run)); } catch (_) {} }
  return run;
}

async function getRun(env, runId) {
  let run = RUNS.get(runId);
  if (!run && env?.KV) { try { const r = await env.KV.get(`run:${runId}`); if (r) run = JSON.parse(r); } catch (_) {} }
  return run || null;
}

async function createBatch(env, batchId, data) {
  const batch = {
    batch_id: batchId, status: 'running', phase: data.phase || 'lightning',
    mode: data.mode || 'lightning', product: data.product || '',
    industry: data.industry || '', slug: data.slug || '',
    run_ids: data.runIds || [], completed_runs: [], created_at: Date.now(), events: [],
  };
  BATCHES.set(batchId, batch);
  if (env?.KV) { try { await env.KV.put(`batch:${batchId}`, JSON.stringify(batch)); } catch (_) {} }
  return batch;
}

async function updateBatch(env, batchId, updates) {
  let batch = BATCHES.get(batchId);
  if (!batch && env?.KV) { try { const r = await env.KV.get(`batch:${batchId}`); if (r) batch = JSON.parse(r); } catch (_) {} }
  if (!batch) return null;
  Object.assign(batch, updates);
  BATCHES.set(batchId, batch);
  if (env?.KV) { try { await env.KV.put(`batch:${batchId}`, JSON.stringify(batch)); } catch (_) {} }
  return batch;
}

async function getBatch(env, batchId) {
  let batch = BATCHES.get(batchId);
  if (!batch && env?.KV) { try { const r = await env.KV.get(`batch:${batchId}`); if (r) batch = JSON.parse(r); } catch (_) {} }
  return batch || null;
}

async function pushBatchEvent(env, batchId, event) {
  let batch = BATCHES.get(batchId) || await getBatch(env, batchId);
  if (!batch) return;
  batch.events = batch.events || [];
  batch.events.push({ ...event, timestamp: Date.now() });
  BATCHES.set(batchId, batch);
  if (env?.KV) { try { await env.KV.put(`batch:${batchId}`, JSON.stringify(batch)); } catch (_) {} }
}

async function markRunComplete(env, runId, batchId, outputText) {
  await updateRun(env, runId, { status: 'completed', completed_at: Date.now(), output_text: outputText.slice(0, 500) });
  if (batchId) {
    const batch = await getBatch(env, batchId);
    if (batch) {
      const completed = batch.completed_runs || [];
      if (!completed.includes(runId)) completed.push(runId);
      await updateBatch(env, batchId, { completed_runs: completed, status: completed.length >= batch.run_ids.length ? 'completed' : 'running' });
    }
  }
}

function genId() {
  return crypto.randomUUID().replace(/-/g, '').slice(0, 12);
}


// ════════════════════════════════════════════════════
// 模块 6: lightning.js (闪电档逻辑)
// ════════════════════════════════════════════════════

/**
 * 闪电档逻辑 · 2 分钟三件套（PRD + UI + Demo）
 */





// 闪电档 spell 路径
const SPELLS = {
  analyze: 'spells/桃子分析咒语.md',
  prd:     'spells/lightning/prd_agent.md',
  ui:      'spells/lightning/ui_agent.md',
  demo:    'spells/lightning/demo_agent.md',
  flow:    'spells/lightning/flow_agent.md',
};

/**
 * 处理 /api/run（分析阶段）
 * 返回 SSE 流
 */
async function handleRun(request, env) {
  const body = await request.json();
  const { product, industry, slug, mode } = body;

  if (!product) {
    return jsonResp({ error: '缺少 product 参数' }, 400);
  }

  const runId = genId();
  const analysisSlug = slug || product.replace(/\s+/g, '_').slice(0, 20);

  // 创建运行记录（status=pending，等 /api/stream 连上再开始调 DeepSeek）
  await createRun(env, runId, {
    agentKey: 'analyze',
    spellPath: SPELLS.analyze,
    product,
    industry,
    mode: mode || 'lightning',
  });

  // 把请求参数存到 KV，供 /api/stream 读取
  if (env?.KV) {
    await env.KV.put(`run_params:${runId}`, JSON.stringify({
      product, industry, slug: analysisSlug, mode: mode || 'lightning',
    }));
  }

  // 返回 JSON（前端拿到 run_id 后跳 results.html 连 /api/stream）
  return jsonResp({
    run_id: runId,
    slug: analysisSlug,
    phase: 'analyze',
    project_dir: `projects/${analysisSlug}`,
  });
}

/**
 * 处理 /api/generate（生成阶段 · 闪电档）
 * 并发 PRD + UI → 串行 Demo
 */
async function handleGenerate(request, env, ctx) {
  const body = await request.json();
  const { analyze_run_id, analysis_text, product, industry, slug, mode } = body;

  const batchId = genId();
  const today = new Date().toISOString().split('T')[0];
  const analysisSlug = slug || product?.replace(/\s+/g, '_').slice(0, 20) || 'project';

  const baseVars = {
    PRODUCT_REQUEST: product || '',
    INDUSTRY: industry || '通用',
    PROJECT_SLUG: analysisSlug,
    TODAY: today,
    ANALYSIS_CONTEXT: analysis_text || '',
    INDUSTRY_EXPERT_CONTEXT: '',
  };

  // 立即返回 batch_id，后台执行 Agent
  const bgWork = (async () => {
    try {
      baseVars.INDUSTRY_EXPERT_CONTEXT = await loadIndustryExpert(env, industry);
      if (mode === 'lightning' || !mode) {
        await runLightningBg(env, batchId, baseVars);
      } else {
        await runStandardBg(env, batchId, baseVars);
      }
    } catch (err) {
      console.error('Generate bg error:', err);
      try { await updateBatch(env, batchId, { status: 'failed', error: err.message }); } catch(_) {}
    }
  })();

  // ctx.waitUntil 让 Worker 在返回响应后继续执行
  if (ctx?.waitUntil) ctx.waitUntil(bgWork);

  // 先创建 batch 记录再返回
  await createBatch(env, batchId, {
    phase: mode === 'lightning' || !mode ? 'lightning' : 'standard',
    mode: mode || 'lightning',
    product: product || '',
    industry: industry || '',
    slug: analysisSlug,
    runIds: [],
  });

  return jsonResp({
    batch_id: batchId,
    mode: mode || 'lightning',
    status: 'running',
    run_ids: {},
  });
}

/**
 * 闪电档（后台执行）：并发 PRD + UI → 串行 Demo
 */
async function runLightningBg(env, batchId, vars) {
  const prdRunId = genId();
  const uiRunId = genId();
  const demoRunId = genId();

  // 创建批次
  await createBatch(env, batchId, {
    phase: 'lightning',
    mode: 'lightning',
    product: vars.PRODUCT_REQUEST,
    industry: vars.INDUSTRY,
    slug: vars.PROJECT_SLUG,
    runIds: [prdRunId, uiRunId, demoRunId],
  });

  // 创建运行记录
  await createRun(env, prdRunId, { agentKey: 'prd', spellPath: SPELLS.prd, batchId, ...vars });
  await createRun(env, uiRunId, { agentKey: 'ui', spellPath: SPELLS.ui, batchId, ...vars });
  await createRun(env, demoRunId, { agentKey: 'demo', spellPath: SPELLS.demo, batchId, ...vars });

  // 并发执行 PRD + UI
  const knowledgeTypes = ['prd', 'html'];
  const [prdSpell, uiSpell] = await Promise.all([
    loadSpell(env, SPELLS.prd, vars, { knowledgeTypes: ['prd'] }),
    loadSpell(env, SPELLS.ui, vars, { knowledgeTypes: ['html'] }),
  ]);

  await pushBatchEvent(env, batchId, { type: 'lightning_start', agents: ['prd', 'ui'] });

  const [prdText, uiText] = await Promise.all([
    runAgent(env, prdRunId, batchId, prdSpell),
    runAgent(env, uiRunId, batchId, uiSpell),
  ]);

  await pushBatchEvent(env, batchId, { type: 'prd_ui_done' });

  // 串行执行 Demo（需要 PRD + UI 的输出作为上下文）
  const demoVars = {
    ...vars,
    PRD_CONTEXT: prdText.slice(0, 6000),
    UI_CONTEXT: uiText.slice(0, 4000),
    USER_INPUT: `基于以上 PRD 和 UI 规格，生成一个可交互的 HTML Demo。产品：${vars.PRODUCT_REQUEST}`,
  };

  const demoSpell = await loadSpell(env, SPELLS.demo, demoVars, { knowledgeTypes: ['html', 'demo'] });
  const demoText = await runAgent(env, demoRunId, batchId, demoSpell);

  await pushBatchEvent(env, batchId, { type: 'lightning_done' });

  // 后台执行，不返回 Response
  await updateBatch(env, batchId, { status: 'completed' });
}

/**
 * 标准档（后台执行）：按阶段顺序执行 Agent
 */
async function runStandardBg(env, batchId, vars) {
  // 标准档先跑 P1 的 agent
  const p1Agents = ['market', 'competitor', 'n34'];
  const today = new Date().toISOString().split('T')[0];

  for (const agentKey of p1Agents) {
    const agentInfo = STANDARD_SPELL_MAP[agentKey];
    if (!agentInfo || !BUNDLE[agentInfo.spell]) continue;

    const runId = genId();
    await createRun(env, runId, { agentKey, spellPath: agentInfo.spell, batchId, mode: 'standard' });

    try {
      const spell = await loadSpell(env, agentInfo.spell, {
        ...vars,
        USER_INPUT: `请执行任务。产品：${vars.PRODUCT_REQUEST}`,
      });
      const stream = await callDeepSeekStream(env, spell.system, spell.user);
      const fullText = await collectStreamText(stream);
      const files = parseOutputFiles(fullText);
      await saveFilesToR2(env, batchId, files);
      await markRunComplete(env, runId, batchId, fullText);
      await pushBatchEvent(env, batchId, { type: 'agent_done', key: agentKey, run_id: runId });
    } catch (err) {
      await updateRun(env, runId, { status: 'failed', error: err.message });
      await pushBatchEvent(env, batchId, { type: 'agent_error', key: agentKey, error: err.message });
    }
  }

  // P1 完成，等待 CEO Gate
  await updateBatch(env, batchId, { status: 'gate_pending', pending_phases: ['p3', 'p4', 'p5', 'p6'] });
  await pushBatchEvent(env, batchId, { type: 'p1_done' });
}

/**
 * 执行单个 Agent：调 DeepSeek → 解析输出 → 存 R2 → 更新状态
 */
async function runAgent(env, runId, batchId, spell) {
  try {
    const stream = await callDeepSeekStream(env, spell.system, spell.user);
    const fullText = await collectStreamText(stream);

    // 解析输出文件并存 R2
    const files = parseOutputFiles(fullText);
    await saveFilesToR2(env, batchId, files);

    // 更新状态
    await markRunComplete(env, runId, batchId, fullText);

    return fullText;
  } catch (err) {
    await markRunComplete(env, runId, batchId, `ERROR: ${err.message}`);
    throw err;
  }
}

/**
 * 处理 /api/stream/{runId}（流式输出 · 用于分析阶段实时展示）
 */
async function handleStream(runId, env) {
  const run = await getRun(env, runId);
  if (!run) return jsonResp({ error: 'Run not found' }, 404);

  // 如果已完成，直接返回结果（Claude CLI 兼容格式）
  if (run.status === 'completed') {
    const encoder = new TextEncoder();
    const msgId = 'msg_' + runId;
    const body = new ReadableStream({
      start(controller) {
        controller.enqueue(encoder.encode(formatClaudeSSE(msgId, run.output_text)));
        controller.enqueue(encoder.encode(`event: done\ndata: {}\n\n`));
        controller.close();
      },
    });
    return new Response(body, {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        'Access-Control-Allow-Origin': '*',
      },
    });
  }

  // 如果是 pending/running 状态 → 实时调 DeepSeek 流式输出
  if (run.status === 'running' || run.agent_key === 'analyze') {
    // 读取请求参数
    const paramsRaw = env?.KV ? await env.KV.get(`run_params:${runId}`) : null;
    const params = paramsRaw ? JSON.parse(paramsRaw) : {};

    const product = params.product || run.product || '';
    const industry = params.industry || run.industry || '';
    const analysisSlug = params.slug || product.replace(/\s+/g, '_').slice(0, 20);

    // 加载分析 spell
    const industryContext = await loadIndustryExpert(env, industry);
    const today = new Date().toISOString().split('T')[0];

    const { system, user } = await loadSpell(env, SPELLS.analyze, {
      PRODUCT_REQUEST: product,
      INDUSTRY: industry || '通用',
      PROJECT_SLUG: analysisSlug,
      TODAY: today,
      INDUSTRY_EXPERT_CONTEXT: industryContext,
      USER_INPUT: `请分析以下产品方向：${product}${industry ? '，行业：' + industry : ''}`,
    }, { injectKnowledge: false });

    // 流式调用 DeepSeek
    const deepseekStream = await callDeepSeekStream(env, system, user);

    // 返回 SSE 流
    return new Response(transformToFrontendSSE(deepseekStream, runId), {
      headers: {
        'Content-Type': 'text/event-stream',
        'Cache-Control': 'no-cache',
        'Access-Control-Allow-Origin': '*',
      },
    });
  }

  return jsonResp({ error: 'Run not streamable', run_status: run.status });
}

// ── 辅助函数 ──

/**
 * 将 DeepSeek SSE 流转换成前端期望的 Claude CLI stream-json 兼容格式
 *
 * 前端期望格式（es.onmessage）：
 *   { type: "assistant", message: { id: "msg_xxx", content: [{ type: "text", text: "累积全文" }] } }
 *
 * 前端用 lastText 做增量：c.text.slice(lastText.length) 取新增部分
 * 所以每条 SSE 的 text 必须是累积全文，不是增量。
 */
function transformToFrontendSSE(deepseekStream, runId) {
  const reader = deepseekStream.getReader();
  const decoder = new TextDecoder();
  const encoder = new TextEncoder();
  let buffer = '';
  let fullText = '';
  let sentHello = false;
  const msgId = 'msg_' + runId;

  return new ReadableStream({
    async pull(controller) {
      if (!sentHello) {
        // hello 事件不用 event: 前缀，前端不监听它（analyze 阶段用 onmessage）
        sentHello = true;
      }

      while (true) {
        const { done, value } = await reader.read();
        if (done) {
          if (buffer.trim()) {
            fullText = extractText(buffer, fullText);
          }
          // 发最终完整文本
          controller.enqueue(encoder.encode(formatClaudeSSE(msgId, fullText)));
          // done 事件
          controller.enqueue(encoder.encode(`event: done\ndata: {}\n\n`));
          controller.close();
          return;
        }

        buffer += decoder.decode(value, { stream: true });
        const lines = buffer.split('\n');
        buffer = lines.pop() || '';

        let hasNew = false;
        for (const line of lines) {
          if (!line.startsWith('data: ') || line === 'data: [DONE]') continue;
          try {
            const json = JSON.parse(line.slice(6));
            const text = json.choices?.[0]?.delta?.content || '';
            if (text) {
              fullText += text;
              hasNew = true;
            }
          } catch (_) {}
        }

        if (hasNew) {
          // 发送累积全文（匹配前端的 lastText 增量逻辑）
          controller.enqueue(encoder.encode(formatClaudeSSE(msgId, fullText)));
          return; // 让浏览器处理
        }
      }
    },
    cancel() {
      reader.cancel();
    },
  });
}

/**
 * 格式化成 Claude CLI stream-json 兼容的 SSE 数据行
 */
function formatClaudeSSE(msgId, fullText) {
  const payload = {
    type: 'assistant',
    message: {
      id: msgId,
      content: [{ type: 'text', text: fullText }],
    },
  };
  return `data: ${JSON.stringify(payload)}\n\n`;
}

function extractText(buf, currentText) {
  for (const line of buf.split('\n')) {
    if (!line.startsWith('data: ') || line === 'data: [DONE]') continue;
    try {
      const json = JSON.parse(line.slice(6));
      const text = json.choices?.[0]?.delta?.content || '';
      if (text) currentText += text;
    } catch (_) {}
  }
  return currentText;
}

function jsonResp(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      'Access-Control-Allow-Origin': '*',
    },
  });
}



