/**
 * GET /api/analyze_cards/:runId
 * 从分析结果中提取认知卡片 JSON
 */
async function handleAnalyzeCards(runId, env) {
  const run = await getRun(env, runId);
  if (!run) return jsonResp({ error: 'Run not found' }, 404);

  // 尝试从 KV 读完整文本（KV 只存摘要，尝试从 R2 读完整版）
  let text = run.output_text || '';
  if (text.length < 200 && run.batch_id) {
    // 尝试从 R2 读 log
    const fullText = await readFile(env, `projects/${run.batch_id}/${runId}.log`);
    if (fullText) text = fullText;
  }

  if (!text) return jsonResp({ error: 'No analysis text found' }, 404);

  // 提取 COGNITIVE_CARDS_JSON 块
  const cards = extractCogCards(text);
  if (cards) return jsonResp({ cards });

  return jsonResp({ error: 'Cards not found in analysis', cards: [] }, 200);
}

function extractCogCards(text) {
  // 匹配 <!-- COGNITIVE_CARDS_JSON 块
  const jsonMatch = text.match(/<!--\s*COGNITIVE_CARDS_JSON\s*([\s\S]*?)-->/);
  if (jsonMatch) {
    try {
      return JSON.parse(jsonMatch[1].trim());
    } catch (_) {}
  }
  // 匹配 ```json 块（备选）
  const codeMatch = text.match(/```json\s*([\s\S]*?)```/);
  if (codeMatch) {
    try {
      const parsed = JSON.parse(codeMatch[1].trim());
      if (Array.isArray(parsed)) return parsed;
      if (parsed.cards) return parsed.cards;
    } catch (_) {}
  }
  return null;
}

