/**
 * POST /api/gate
 * CEO Gate 评分（纯算术）
 */
async function handleGate(request, env) {
  const body = await request.json();
  const { batch_id, scores } = body;

  if (!scores) return jsonResp({ error: 'scores required' }, 400);

  const labels = ['市场空间', '竞品壁垒', 'AI边界', '用户画像', '产品定位'];
  const keys = ['q1', 'q2', 'q3', 'q4', 'q5'];
  const detail = {};
  let total = 0;
  let hasZero = false;

  for (let i = 0; i < 5; i++) {
    const val = Math.max(0, Math.min(100, parseInt(scores[keys[i]]) || 0));
    detail[labels[i]] = val;
    total += val;
    if (val === 0) hasZero = true;
  }

  let decision, msg;
  if (total >= 400 && !hasZero) {
    decision = 'pass';
    msg = `总分 ${total}/500 · 全部达标 · 通过 CEO Gate · 可进入 P3`;
  } else if (total < 300 || (hasZero && total < 400)) {
    decision = 'stop';
    msg = `总分 ${total}/500 · 未达标 · 建议终止或大幅修改`;
  } else {
    decision = 'redo';
    msg = `总分 ${total}/500 · 需补强${hasZero ? '（有 0 分项）' : ''} · 回炉后重审`;
  }

  // 记录到批次
  if (batch_id && env?.KV) {
    await updateBatch(env, batch_id, { gate_result: { decision, total, detail } });
  }

  return jsonResp({ decision, total, detail, msg, can_proceed: decision === 'pass' });
}

/**
 * POST /api/project-type
 * 项目类型分类（关键词匹配）
 */
async function handleProjectType(request, _env) {
  const body = await request.json();
  const { product, industry } = body;
  const text = `${product || ''} ${industry || ''}`.toLowerCase();

  // 端类型判断
  let end_type = 'C';
  if (/政[企务]|公安|军工|档案|信创/.test(text)) end_type = 'G';
  else if (/[企bB]端|[Ss]aa[Ss]|[Cc]rm|erp|mes|oa|管理系统|后台|工单|审批/.test(text)) end_type = 'B';

  // AI 风险
  let ai_risk = 'low';
  if (/金融|信贷|医疗|法律|军工/.test(text)) ai_risk = 'high';
  else if (/教育|汽车|保险/.test(text)) ai_risk = 'medium';

  // 推荐模型
  let recommended_model = 'GPT-4o / Claude / DeepSeek-V3';
  if (end_type === 'G') recommended_model = 'Qwen2-72B / GLM-4（国产信创）';
  else if (ai_risk === 'high' && end_type === 'B') recommended_model = 'Qwen2-72B / DeepSeek-V3（需私有化）';

  // 合规焦点
  const compliance_focus = [];
  if (end_type === 'G') compliance_focus.push('等保三级', '信创', '国产模型');
  if (/金融|信贷/.test(text)) compliance_focus.push('金融监管', '反洗钱');
  if (/医疗/.test(text)) compliance_focus.push('HIPAA', '医疗数据');
  if (/跨境|海外|出海/.test(text)) compliance_focus.push('GDPR', '数据跨境');
  compliance_focus.push('个保法', 'AI管理办法');

  // 行业匹配
  const industries = {
    金融: /金融|银行|保险|信贷|理财|支付/,
    医疗: /医疗|健康|三甲|诊所|药/,
    教育: /教育|学习|课程|k12|培训/,
    电商: /电商|购物|商城|零售/,
    制造: /制造|工厂|工业|mes/,
    游戏: /游戏|手游|端游/,
    宠物: /宠物|猫|狗/,
    汽车: /汽车|车联|出行/,
    家装: /家装|装修|设计/,
    短视频: /短视频|直播/,
    内容: /内容|媒体|资讯/,
    企业SaaS: /saas|crm|erp|oa/,
    跨境电商: /跨境|出海/,
  };

  let matched_industry = '通用';
  for (const [name, pattern] of Object.entries(industries)) {
    if (pattern.test(text)) { matched_industry = name; break; }
  }

  return jsonResp({
    id: `${end_type.toLowerCase()}_${matched_industry}`,
    name: `${end_type}端·${matched_industry}`,
    end_type,
    ai_risk,
    recommended_model,
    compliance_focus,
    model_hard_rule: end_type === 'G',
    north_star_candidates: end_type === 'C'
      ? ['DAU', 'MAU', '用户留存率', 'NPS', '转化率']
      : end_type === 'B'
        ? ['企业客户数', 'ARR', '续约率', '客户满意度']
        : ['采购额', '覆盖率', '合规达标率'],
    phase_priority: ai_risk === 'high' ? ['p1', 'p5', 'p2', 'p3', 'p4', 'p6'] : ['p1', 'p2', 'p3', 'p4', 'p5', 'p6'],
  });
}

