/**
 * POST /api/revise
 * 带反馈重新生成文档
 */
async function handleRevise(request, env) {
  const body = await request.json();
  const { batch_id, key, feedback } = body;

  if (!batch_id) return jsonResp({ error: 'batch_id required' }, 400);
  if (!feedback) return jsonResp({ error: 'feedback required' }, 400);
  if (!key) return jsonResp({ error: 'key required' }, 400);

  const batch = await getBatch(env, batch_id);
  if (!batch) return jsonResp({ error: 'Batch not found' }, 404);

  const agentInfo = STANDARD_SPELL_MAP[key] || STANDARD_SPELL_MAP[`lightning-${key}`];
  if (!agentInfo) return jsonResp({ error: `Unknown agent key: ${key}` }, 400);

  const runId = genId();
  await createRun(env, runId, { agentKey: key, spellPath: agentInfo.spell, batchId: batch_id, mode: 'revise' });

  // 收集已有项目文件作为上下文
  const projectContext = await collectProjectContext(env, batch_id);
  const industryContext = await loadIndustryExpert(env, batch.industry);
  const today = new Date().toISOString().split('T')[0];

  const spell = await loadSpell(env, agentInfo.spell, {
    PRODUCT_REQUEST: batch.product || '',
    INDUSTRY: batch.industry || '通用',
    PROJECT_SLUG: batch.slug || '',
    TODAY: today,
    ANALYSIS_CONTEXT: projectContext,
    INDUSTRY_EXPERT_CONTEXT: industryContext,
    USER_INPUT: `请根据以下反馈修改文档：\n\n${feedback}\n\n已有项目文件摘要：\n${projectContext.slice(0, 4000)}`,
  });

  // 在 spell 中注入修改指令
  const revisedSystem = spell.system + `\n\n---\n## ⚠️ 修改指令（必须遵守）\n\n用户对之前的输出不满意，要求修改：\n\n${feedback}\n\n请重新输出完整文档，融入以上反馈。`;

  // 后台执行
  const execPromise = (async () => {
    try {
      const stream = await callDeepSeekStream(env, revisedSystem, spell.user);
      const fullText = await collectStreamText(stream);
      const files = parseOutputFiles(fullText);
      await saveFilesToR2(env, batch_id, files);
      await markRunComplete(env, runId, batch_id, fullText);
      await pushBatchEvent(env, batch_id, { type: 'revise_done', key, run_id: runId });
    } catch (err) {
      await updateRun(env, runId, { status: 'failed', error: err.message });
      await pushBatchEvent(env, batch_id, { type: 'revise_error', key, error: err.message });
    }
  })();

  // 不 await，让 worker 后台执行（Cloudflare waitUntil 需要 ctx，这里用简单方式）
  // 注意：Cloudflare Worker 会等所有 Promise 完成

  return jsonResp({ run_id: runId, key });
}

