/**
 * GET /api/reviewer-verdict/:batchId
 * 解析审核报告结果
 */
async function handleReviewerVerdict(batchId, env) {
  const auditText = await readFile(env, `projects/${batchId}/AUDIT_REPORT.md`);
  if (!auditText) return jsonResp({ verdict: 'pending', reason: 'AUDIT_REPORT.md 尚未生成' });

  // 解析 [VERDICT: xxx] 标签
  const verdictMatch = auditText.match(/\[VERDICT:\s*(PASS|BLOCK|CONDITIONAL)\s*\]/i);
  const p0Match = auditText.match(/P0_COUNT:\s*(\d+)/i);
  const p1Match = auditText.match(/P1_COUNT:\s*(\d+)/i);
  const blockMatch = auditText.match(/BLOCK_REASON:\s*(.+)/i);

  if (verdictMatch) {
    const verdictRaw = verdictMatch[1].toUpperCase();
    return jsonResp({
      verdict: verdictRaw === 'BLOCK' ? 'FAIL' : verdictRaw,
      verdict_raw: verdictRaw,
      p0_count: p0Match ? parseInt(p0Match[1]) : 0,
      p1_count: p1Match ? parseInt(p1Match[1]) : null,
      p0_failures: extractP0Lines(auditText).slice(0, 10),
      block_reason: blockMatch ? blockMatch[1].trim() : null,
      source: 'explicit',
    });
  }

  // 启发式扫描
  const p0Lines = extractP0Lines(auditText);
  const hasFail = p0Lines.length > 0;
  return jsonResp({
    verdict: hasFail ? 'FAIL' : 'PASS',
    verdict_raw: hasFail ? 'BLOCK' : 'PASS',
    p0_count: p0Lines.length,
    p1_count: null,
    p0_failures: p0Lines.slice(0, 10),
    block_reason: hasFail ? p0Lines[0] : null,
    source: 'heuristic',
  });
}

function extractP0Lines(text) {
  const lines = text.split('\n');
  const p0 = [];
  for (const line of lines) {
    if (/P0/i.test(line) && /(FAIL|失败|❌|BLOCK)/i.test(line)) {
      p0.push(line.replace(/^[\s\-*#]+/, '').slice(0, 200));
    }
  }
  return p0;
}

/**
 * GET /api/audit-block-items/:batchId
 * 提取 P0 失败项及关联 agent
 */
async function handleAuditBlockItems(batchId, env) {
  const auditText = await readFile(env, `projects/${batchId}/AUDIT_REPORT.md`);
  if (!auditText) return jsonResp({ verdict: 'pending', p0_items: [] });

  const verdictMatch = auditText.match(/\[VERDICT:\s*(PASS|BLOCK|CONDITIONAL)\s*\]/i);
  const verdict = verdictMatch ? verdictMatch[1].toUpperCase() : 'pending';

  const p0Lines = extractP0Lines(auditText);
  const p0Items = p0Lines.slice(0, 10).map(line => ({
    issue: line.slice(0, 200),
    agent_key: guessAgentFromIssue(line),
  }));

  return jsonResp({ verdict, p0_items: p0Items });
}

/** 从 P0 描述猜测负责的 agent */
function guessAgentFromIssue(text) {
  const hints = {
    'PRD|需求|功能': 'prd',
    '市场|竞品|TAM|SAM': 'market',
    '用户|画像|旅程': 'user',
    '设计|UI|交互|原型': 'proto',
    '技术|架构|API': 'tech',
    'Demo|demo|HTML': 'demo',
    '合规|隐私|GDPR': 'compliance',
    '指标|数据|埋点': 'metrics',
    '运营|上线|ASO': 'ops',
    'AI|模型|训练': 'n34',
  };
  for (const [pattern, agent] of Object.entries(hints)) {
    if (new RegExp(pattern, 'i').test(text)) return agent;
  }
  return 'prd'; // 默认
}

/**
 * POST /api/rerun-agent
 * 审核失败后重跑某个 agent
 */
async function handleRerunAgent(request, env) {
  const body = await request.json();
  const { batch_id, agent_key, extra_context } = body;

  if (!batch_id) return jsonResp({ error: 'batch_id required' }, 400);
  if (!agent_key) return jsonResp({ error: 'agent_key required' }, 400);

  const batch = await getBatch(env, batch_id);
  if (!batch) return jsonResp({ error: 'Batch not found' }, 404);

  const agentInfo = STANDARD_SPELL_MAP[agent_key];
  if (!agentInfo) return jsonResp({ error: `No spell for ${agent_key}` }, 400);

  const projectContext = await collectProjectContext(env, batch_id);
  const industryContext = await loadIndustryExpert(env, batch.industry);
  const today = new Date().toISOString().split('T')[0];

  const runId = genId();
  await createRun(env, runId, { agentKey: agent_key, spellPath: agentInfo.spell, batchId: batch_id, mode: 'rerun' });

  let extraPrompt = '';
  if (extra_context) {
    extraPrompt = `\n\n---\n## ⚠️ 审查员反馈（必须修复）\n\n${extra_context}\n\n请针对以上问题重新输出完整文档。`;
  }

  const spell = await loadSpell(env, agentInfo.spell, {
    PRODUCT_REQUEST: batch.product || '',
    INDUSTRY: batch.industry || '通用',
    PROJECT_SLUG: batch.slug || '',
    TODAY: today,
    ANALYSIS_CONTEXT: projectContext,
    INDUSTRY_EXPERT_CONTEXT: industryContext,
    USER_INPUT: `请重新执行任务。产品：${batch.product || ''}${extra_context ? '\n\n审查反馈：' + extra_context : ''}`,
  });

  (async () => {
    try {
      const stream = await callDeepSeekStream(env, spell.system + extraPrompt, spell.user);
      const fullText = await collectStreamText(stream);
      const files = parseOutputFiles(fullText);
      await saveFilesToR2(env, batch_id, files);
      await markRunComplete(env, runId, batch_id, fullText);
      await pushBatchEvent(env, batch_id, { type: 'rerun_done', key: agent_key, run_id: runId });
    } catch (err) {
      await updateRun(env, runId, { status: 'failed', error: err.message });
      await pushBatchEvent(env, batch_id, { type: 'rerun_error', key: agent_key, error: err.message });
    }
  })();

  return jsonResp({ run_id: runId });
}

/**
 * POST /api/start-next-phase
 * 推进下一阶段（执行队列中的所有 agent）
 */
async function handleStartNextPhase(request, env) {
  const body = await request.json();
  const { batch_id, user_notes } = body;

  if (!batch_id) return jsonResp({ error: 'batch_id required' }, 400);
  const batch = await getBatch(env, batch_id);
  if (!batch) return jsonResp({ done: true, error: 'Batch not found' });

  // 读取 agent 队列
  const queueRaw = env?.KV ? await env.KV.get(`queue:${batch_id}`) : null;
  const queue = queueRaw ? JSON.parse(queueRaw) : [];

  if (queue.length === 0) return jsonResp({ done: true, new_runs: {} });

  // 保存用户笔记
  if (user_notes && env?.R2) {
    const key = `projects/${batch_id}/USER_NOTES.md`;
    const existing = await readFile(env, key) || '';
    await env.R2.put(key, existing + `\n\n## ${new Date().toISOString()}\n${user_notes}`);
  }

  const projectContext = await collectProjectContext(env, batch_id);
  const industryContext = await loadIndustryExpert(env, batch.industry);
  const today = new Date().toISOString().split('T')[0];
  const newRuns = {};

  // 执行队列中所有 agent
  for (const agentKey of queue) {
    const agentInfo = STANDARD_SPELL_MAP[agentKey];
    if (!agentInfo) continue;

    const runId = genId();
    await createRun(env, runId, { agentKey, spellPath: agentInfo.spell, batchId: batch_id, mode: 'standard' });
    newRuns[agentKey] = runId;

    const spell = await loadSpell(env, agentInfo.spell, {
      PRODUCT_REQUEST: batch.product || '',
      INDUSTRY: batch.industry || '通用',
      PROJECT_SLUG: batch.slug || '',
      TODAY: today,
      ANALYSIS_CONTEXT: projectContext,
      INDUSTRY_EXPERT_CONTEXT: industryContext,
      USER_INPUT: `请执行任务。产品：${batch.product || ''}${user_notes ? '\n\n用户补充：' + user_notes : ''}`,
    });

    // 后台执行每个 agent
    (async () => {
      try {
        const stream = await callDeepSeekStream(env, spell.system, spell.user);
        const fullText = await collectStreamText(stream);
        const files = parseOutputFiles(fullText);
        await saveFilesToR2(env, batch_id, files);
        await markRunComplete(env, runId, batch_id, fullText);
        await pushBatchEvent(env, batch_id, { type: 'agent_done', key: agentKey, run_id: runId });
      } catch (err) {
        await updateRun(env, runId, { status: 'failed', error: err.message });
        await pushBatchEvent(env, batch_id, { type: 'agent_error', key: agentKey, error: err.message });
      }
    })();
  }

  // 清空队列
  if (env?.KV) {
    await env.KV.put(`queue:${batch_id}`, '[]');
  }

  // 更新批次
  const allRunIds = [...(batch.run_ids || []), ...Object.values(newRuns)];
  await updateBatch(env, batch_id, { run_ids: allRunIds });

  return jsonResp({ new_runs: newRuns, done: false });
}

/**
 * POST /api/advance-phase
 * Gate 通过后解锁后续阶段
 */
async function handleAdvancePhase(request, env) {
  const body = await request.json();
  const { batch_id, phases } = body;

  if (!batch_id) return jsonResp({ error: 'batch_id required' }, 400);
  const batch = await getBatch(env, batch_id);
  if (!batch) return jsonResp({ error: 'Batch not found' }, 404);

  // 确定要执行的阶段
  const targetPhases = phases || batch.pending_phases || ['p3', 'p4', 'p5', 'p6'];

  // 收集所有 agent keys
  const allAgents = [];
  for (const phase of targetPhases) {
    const agents = PHASE_AGENT_MAP[phase] || [];
    allAgents.push(...agents);
  }

  if (allAgents.length === 0) return jsonResp({ ok: true, new_runs: {}, sequential_queue: [] });

  // 第一个 agent 立即启动，其余放入队列
  const firstAgent = allAgents[0];
  const restAgents = allAgents.slice(1);

  // 存入队列
  if (env?.KV) {
    await env.KV.put(`queue:${batch_id}`, JSON.stringify(restAgents));
  }

  // 启动第一个 agent
  const projectContext = await collectProjectContext(env, batch_id);
  const industryContext = await loadIndustryExpert(env, batch.industry);
  const today = new Date().toISOString().split('T')[0];

  const agentInfo = STANDARD_SPELL_MAP[firstAgent];
  const runId = genId();
  await createRun(env, runId, { agentKey: firstAgent, spellPath: agentInfo.spell, batchId: batch_id, mode: 'standard' });

  const spell = await loadSpell(env, agentInfo.spell, {
    PRODUCT_REQUEST: batch.product || '',
    INDUSTRY: batch.industry || '通用',
    PROJECT_SLUG: batch.slug || '',
    TODAY: today,
    ANALYSIS_CONTEXT: projectContext,
    INDUSTRY_EXPERT_CONTEXT: industryContext,
    USER_INPUT: `请执行任务。产品：${batch.product || ''}`,
  });

  (async () => {
    try {
      const stream = await callDeepSeekStream(env, spell.system, spell.user);
      const fullText = await collectStreamText(stream);
      const files = parseOutputFiles(fullText);
      await saveFilesToR2(env, batch_id, files);
      await markRunComplete(env, runId, batch_id, fullText);
      await pushBatchEvent(env, batch_id, { type: 'agent_done', key: firstAgent, run_id: runId });
    } catch (err) {
      await updateRun(env, runId, { status: 'failed', error: err.message });
    }
  })();

  await updateBatch(env, batch_id, { pending_phases: [] });

  return jsonResp({
    ok: true,
    new_runs: { [firstAgent]: runId },
    sequential_queue: restAgents,
  });
}

/**
 * 收集批次下已有项目文件作为上下文
 */
async function collectProjectContext(env, batchId) {
  const files = await listBatchFiles(env, batchId);
  if (files.length === 0) return '';

  let context = '';
  for (const file of files.slice(0, 10)) { // 最多读 10 个文件
    const content = await readFile(env, file.path);
    if (content) {
      const truncated = content.length > 3000 ? content.slice(0, 3000) + '\n...(截断)' : content;
      context += `\n\n### ${file.filename}\n${truncated}`;
    }
  }
  return context;
}


// ════════════════════════════════════════════════════
// 模块 7: 路由入口 (原 [[catchall]].js)
// ════════════════════════════════════════════════════

/**
 * 桃子公司 Cloudflare Pages Function · /api/* 统一路由
 *
 * 文件名 [[catchall]].js 表示匹配 /api/ 下的所有路径
 * 参考：https://developers.cloudflare.com/pages/functions/routing/
 */




async function onRequest(context) {
  const { request, env, params } = context;
  const url = new URL(request.url);
  // params.catchall 是数组，如 ['stream', 'abc123']
  const subPath = (params.catchall || []).join('/');
  const path = `/api/${subPath}`;

  // CORS 预检
  if (request.method === 'OPTIONS') {
    return corsResponse();
  }

  try {
    const response = await route(path, request, env);
    return addCors(response);
  } catch (err) {
    console.error('API error:', err);
    return addCors(jsonResp({ error: err.message }, 500));
  }
}

async function route(path, request, env, ctx) {
  // POST /api/run · 启动分析
  if (path === '/api/run' && request.method === 'POST') {
    return handleRun(request, env);
  }

  // POST /api/generate · 启动生成
  if (path === '/api/generate' && request.method === 'POST') {
    return handleGenerate(request, env, ctx);
  }

  // GET /api/stream/:runId · SSE 实时流
  const streamMatch = path.match(/^\/api\/stream\/([a-z0-9]+)$/);
  if (streamMatch && request.method === 'GET') {
    return handleStream(streamMatch[1], env);
  }

  // GET /api/batch-status/:batchId · 批次状态
  const batchStatusMatch = path.match(/^\/api\/batch-status\/([a-z0-9]+)$/);
  if (batchStatusMatch && request.method === 'GET') {
    const batch = await getBatch(env, batchStatusMatch[1]);
    if (!batch) return jsonResp({ error: 'Batch not found' }, 404);
    return jsonResp(batch);
  }

  // GET /api/batch-events/:batchId · 批次事件（SSE）
  const batchEventsMatch = path.match(/^\/api\/batch-events\/([a-z0-9]+)$/);
  if (batchEventsMatch && request.method === 'GET') {
    const batch = await getBatch(env, batchEventsMatch[1]);
    if (!batch) return jsonResp({ error: 'Batch not found' }, 404);

    const encoder = new TextEncoder();
    const body = new ReadableStream({
      start(controller) {
        for (const evt of (batch.events || [])) {
          controller.enqueue(encoder.encode(`event: ${evt.type}\ndata: ${JSON.stringify(evt)}\n\n`));
        }
        if (batch.status === 'completed') {
          controller.enqueue(encoder.encode(`event: done\ndata: ${JSON.stringify({ batch_id: batch.batch_id })}\n\n`));
        }
        controller.close();
      },
    });

    return new Response(body, {
      headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache' },
    });
  }

  // GET /api/files/:id · 文件列表
  const filesMatch = path.match(/^\/api\/files\/([a-z0-9]+)$/);
  if (filesMatch && request.method === 'GET') {
    const id = filesMatch[1];
    const batch = await getBatch(env, id);
    if (batch) {
      const files = await listBatchFiles(env, id);
      return jsonResp({ batch_id: id, files });
    }
    const run = await getRun(env, id);
    if (run && run.batch_id) {
      const files = await listBatchFiles(env, run.batch_id);
      return jsonResp({ batch_id: run.batch_id, files });
    }
    return jsonResp({ error: 'Not found' }, 404);
  }

  // GET /api/file-content?path=xxx · 读取文件
  if (path === '/api/file-content' && request.method === 'GET') {
    const filePath = new URL(request.url).searchParams.get('path');
    if (!filePath) return jsonResp({ error: '缺少 path 参数' }, 400);
    const content = await readFile(env, filePath);
    if (content === null) return jsonResp({ error: 'File not found' }, 404);
    return new Response(content, {
      headers: { 'Content-Type': 'text/plain; charset=utf-8' },
    });
  }

  // GET /api/model-config · 模型配置
  if (path === '/api/model-config' && request.method === 'GET') {
    return jsonResp({
      model: env.DEEPSEEK_MODEL || 'deepseek-chat',
      max_tokens: parseInt(env.MAX_TOKENS || '8192'),
      provider: 'deepseek',
    });
  }

  // GET /api/health · 健康检查
  if (path === '/api/health') {
    return jsonResp({ status: 'ok', version: '2.0.0', provider: 'deepseek' });
  }

  // GET /api/ping · 兼容旧前端
  if (path === '/api/ping') {
    return jsonResp({ ok: true, service: 'peach-cloud', version: '2.0', model: 'deepseek-v3' });
  }

  // ── Tier 1 接口 ──

  // GET /api/analyze_cards/:runId
  const cardsMatch = path.match(/^\/api\/analyze_cards\/([a-z0-9]+)$/);
  if (cardsMatch && request.method === 'GET') {
    return handleAnalyzeCards(cardsMatch[1], env);
  }

  // POST /api/feedback
  if (path === '/api/feedback' && request.method === 'POST') {
    return handleFeedback(request, env);
  }

  // POST /api/gate
  if (path === '/api/gate' && request.method === 'POST') {
    return handleGate(request, env);
  }

  // POST /api/project-type
  if (path === '/api/project-type' && request.method === 'POST') {
    return handleProjectType(request, env);
  }

  // ── Tier 2 接口 ──

  // POST /api/refine
  if (path === '/api/refine' && request.method === 'POST') {
    return handleRefine(request, env);
  }

  // POST /api/revise
  if (path === '/api/revise' && request.method === 'POST') {
    return handleRevise(request, env);
  }

  // POST /api/start-demo-agent
  if (path === '/api/start-demo-agent' && request.method === 'POST') {
    return handleStartDemoAgent(request, env);
  }

  // POST /api/save-user-decision
  if (path === '/api/save-user-decision' && request.method === 'POST') {
    return handleSaveUserDecision(request, env);
  }

  // POST /api/start-reviewer-agent
  if (path === '/api/start-reviewer-agent' && request.method === 'POST') {
    return handleStartReviewerAgent(request, env);
  }

  // GET /api/reviewer-verdict/:batchId
  const verdictMatch = path.match(/^\/api\/reviewer-verdict\/([a-z0-9]+)$/);
  if (verdictMatch && request.method === 'GET') {
    return handleReviewerVerdict(verdictMatch[1], env);
  }

  // GET /api/audit-block-items/:batchId
  const auditMatch = path.match(/^\/api\/audit-block-items\/([a-z0-9]+)$/);
  if (auditMatch && request.method === 'GET') {
    return handleAuditBlockItems(auditMatch[1], env);
  }

  // POST /api/rerun-agent
  if (path === '/api/rerun-agent' && request.method === 'POST') {
    return handleRerunAgent(request, env);
  }

  // POST /api/start-next-phase
  if (path === '/api/start-next-phase' && request.method === 'POST') {
    return handleStartNextPhase(request, env);
  }

  // POST /api/advance-phase
  if (path === '/api/advance-phase' && request.method === 'POST') {
    return handleAdvancePhase(request, env);
  }

  return jsonResp({ error: 'Not found', path }, 404);
}

// jsonResp defined in lightning.js section

function corsResponse() {
  return new Response(null, {
    headers: {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type',
      'Access-Control-Max-Age': '86400',
    },
  });
}

function addCors(response) {
  const h = new Headers(response.headers);
  h.set('Access-Control-Allow-Origin', '*');
  return new Response(response.body, { status: response.status, headers: h });
}


// ════════════════════════════════════════════════════
// Worker 入口 · export default
// ════════════════════════════════════════════════════

export default {
  async fetch(request, env, ctx) {
    const url = new URL(request.url);

    // /api/* 路径走 API 路由
    if (url.pathname.startsWith('/api/')) {
      // CORS 预检
      if (request.method === 'OPTIONS') {
        return corsResponse();
      }

      try {
        // 从 pathname 提取 subPath · 传入 ctx 用于后台任务
        const subPath = url.pathname;
        const response = await route(subPath, request, env, ctx);
        return addCors(response);
      } catch (err) {
        console.error('API error:', err);
        return addCors(jsonResp({ error: err.message }, 500));
      }
    }

    // 非 API 路径 → 交给 Pages 处理静态文件
    return env.ASSETS.fetch(request);
  },
};
